CONTENT_ANALYSIS_TYPE_CHOICES = ["content-analysis", "reverse-ai-prompt"]


CONTENT_ANALYSIS_SOURCE_TYPE_CHOICES = ["upload", "platform_link"]


CONTENT_ANALYSIS_MEDIA_TYPE_CHOICES = ["video"]


def _add_content_analysis_run_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
    parser.add_argument("--type", choices=CONTENT_ANALYSIS_TYPE_CHOICES, required=True)
    parser.add_argument("--url")
    parser.add_argument("--media-id")
    parser.add_argument("--file")
    parser.add_argument(
        "--media-type", choices=CONTENT_ANALYSIS_MEDIA_TYPE_CHOICES, default="video"
    )
    parser.add_argument("--title")
    parser.add_argument("--description")
    parser.add_argument("--force", action="store_true")
    parser.add_argument("--wait", action="store_true")
    parser.add_argument("--timeout", type=int, default=60)
    parser.add_argument("--poll-interval", type=float, default=2.0)
    parser.add_argument("--dry-run", action="store_true")


def _build_content_analysis_run_arguments(args: argparse.Namespace) -> dict[str, Any]:
    payload = _load_structured_args(args)
    payload["type"] = args.type
    source_fields = [
        bool(args.url),
        bool(args.media_id),
        bool(args.file),
    ]
    if sum(source_fields) != 1:
        raise ValueError(
            "content-analysis +run requires exactly one source: --url, --media-id, or --file."
        )
    payload.update(
        _without_none(
            {
                "url": args.url,
                "media_id": args.media_id,
                "file": args.file,
                "media_type": args.media_type if args.file else None,
                "title": args.title,
                "description": args.description,
                "force_reanalysis": args.force,
                "wait": args.wait,
                "wait_timeout_seconds": args.timeout,
                "poll_interval_seconds": args.poll_interval,
            }
        )
    )
    return payload


def _add_content_analysis_get_arguments(parser: argparse.ArgumentParser) -> None:
    _add_common_adapter_arguments(parser)
