# ---- executors (generated from main.py direct_* chains) ----
async def _execute_get(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    run_id = str(arguments.get("run_id") or "")
    if not run_id:
        raise RuntimeError("content-analysis +get requires --id")
    return agent_domain_result(
        await api_data(
            cfg,
            "GET",
            f"/agent-cli/content-analysis/runs/{run_id}",
            params={"workspace_id": workspace_id},
        )
    )


async def _execute_list(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    return agent_domain_result(
        await api_data(
            cfg,
            "GET",
            "/agent-cli/content-analysis/runs",
            params={"workspace_id": workspace_id, **arguments},
        )
    )


async def _execute_run(ctx: CommandContext) -> Any:
    cfg = ctx.cfg
    arguments = ctx.arguments
    workspace_id = ctx.workspace_id
    api_data = ctx.api_data
    upload_media_file = ctx.upload_media_file
    if not workspace_id:
        raise RuntimeError("missing_workspace")
    payload = dict(arguments)
    file_path = payload.pop("file", None)
    if file_path:
        upload_response = await upload_media_file(
            cfg,
            workspace_id=workspace_id,
            arguments={
                key: value
                for key, value in {
                    "file": file_path,
                    "media_type": payload.pop("media_type", "video"),
                    "title": payload.pop("title", None),
                    "description": payload.pop("description", None),
                }.items()
                if value is not None
            },
        )
        payload["media_id"] = uploaded_media_id(upload_response)
    return agent_domain_result(
        await api_data(
            cfg,
            "POST",
            "/agent-cli/content-analysis/runs",
            json_body={"workspace_id": workspace_id, "payload": payload},
        )
    )


EXECUTORS = {
    "content-analysis.get": direct_enveloped(_execute_get),
    "content-analysis.list": direct_enveloped(_execute_list),
    "content-analysis.run": direct_enveloped(_execute_run),
}


def uploaded_media_id(response: Any) -> str:
    if not isinstance(response, dict):
        raise RuntimeError("media upload did not return a JSON object")
    candidates: list[Any] = [
        response.get("media_id"),
        response.get("id"),
    ]
    data = response.get("data")
    if isinstance(data, dict):
        candidates.extend([data.get("media_id"), data.get("id")])
        asset = data.get("asset")
        if isinstance(asset, dict):
            candidates.extend([asset.get("media_id"), asset.get("id")])
    asset = response.get("asset")
    if isinstance(asset, dict):
        candidates.extend([asset.get("media_id"), asset.get("id")])
    for candidate in candidates:
        if candidate:
            return str(candidate)
    raise RuntimeError("media upload response did not include media_id")
